head.script:
//============================================================================
// id       : se_201_01_02b
// 이름     : import House B/L Freight
// 경로     : 
// 사용계정 : 
// 파라미터 :
//            IN  : 
//            OUT : 
//
// 비고     : 
//           
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     : 
//============================================================================
scwin.userId = "";
scwin.p_lobranCd = "";
scwin.p_lobranNm = "";
scwin.p_seaExgbIm = "";
scwin.p_clntNo = "";

scwin.v_linkcheck = "";
scwin.v_kcomcd = "";
scwin.v_blno = "";
scwin.v_mhno = "";
scwin.v_bkno = "";

scwin.p_no = "";
scwin.p_row_cnt = "";
scwin.p_data = "";
scwin.p_hblno = "";
scwin.p_docuno = "";

scwin.strCurDate = "";   // 서버일자

scwin.statusFlag = "";	// C:Regist, U:Update, I:Init
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.tabNo = 0;
scwin.mhnoFlag = "0"; // 1일때 mhno onloadComplete후 조회.
scwin.exRateCheck = "1"; // 환율 존재 유무	

scwin.exRate1 = "0"; // 환율1  
scwin.exRate2 = "0"; // 환율2  
scwin.crc = ""; // 환종

// hidden 
scwin.hd_kcomcd = "DBEX";
scwin.hd_hhio = "I";
scwin.hd_hhitem = "";
scwin.hd_creadyDt = "";
scwin.hd_hhpcgb = "";
scwin.hd_hhdanggb = "";
scwin.hd_commcustomer = "999999";
scwin.ed_hhbltype = "";

scwin.onpageload = async function () {
    // 세션정보 가져오기
    var memJson = $c.data.getMemInfo();

    scwin.userId = memJson.userId;
    scwin.p_lobranCd = $c.data.getMemInfo("lobranCd");  // 귀속부서코드
    scwin.p_lobranNm = $c.data.getMemInfo("lobranNm");  // 귀속부서 명

    if ($c.gus.cfIsNull(scwin.p_lobranCd)) {
        scwin.p_lobranCd = "";
    }

    var resData = await $c.gus.dsCommonUtil("getCompanyInfoDTO", scwin.p_lobranCd)[0]?.value.split("\n");
    var commDTO = resData.reduce((acc, curr) => {
        let match = curr.match(/^\s*\w+\s+(\w+)\s+=\s+\[(.*)\]/);

        if (match) {
            let key = match[1];
            let value = match[2];

            if (value == "null") value = null;
            acc[key] = value;
        }

        return acc;
    }, {});

    scwin.p_seaExgbIm = commDTO.seaExgbIm || "";
    scwin.p_clntNo = commDTO.clntNo || "";

    // 파라미터 치환
    scwin.v_linkcheck = $c.data.getParameter("linkcheck") || "0";
    scwin.v_kcomcd = $c.data.getParameter("kcomcd") || "DBEX";
    scwin.v_blno = $c.data.getParameter("blno") || "";
    scwin.v_mhno = $c.data.getParameter("mhno") || "";
    scwin.v_bkno = $c.data.getParameter("bkno") || "";

    scwin.p_no = $c.data.getParameter("no") || "";
    scwin.p_row_cnt = $c.data.getParameter("row_cnt") || "";
    scwin.p_data = $c.data.getParameter("data") || "";
    scwin.p_hblno = $c.data.getParameter("hblno") || "";
    scwin.p_docuno = $c.data.getParameter("docuno") || "";

    // 서버일자
    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = async function () {
    $p.setTimeout(async function () {
        // 기본값 세팅
        await scwin.f_initSetTab();
        await scwin.f_DefaultValue();
        await scwin.f_Check();
        await scwin.f_ContainerTypeLoading();
        await scwin.f_CurrencyLoading();
        scwin.f_getParametrSetting(scwin.v_linkcheck);
    }, { "delay": 50 });

};

//---------------------------------------------------------
// Parameter Setting
//---------------------------------------------------------
scwin.f_getParametrSetting = function (gubun) {
    switch (gubun) {
        case "0":
            break;

        case "5": // House B/L에서 옴
            scwin.mhnoFlag = "1";
            if ($c.util.isEmpty(scwin.v_blno)) {
                cnd_ed_hhblno.setValue("");
                cnd_ed_hhblno.focus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_hhblno.setValue(scwin.v_blno);
            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow(0);
            }

            ds_hmhno.setCellData(ds_hmhno.getRowPosition() || 0, "code", scwin.v_mhno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition() || 0, "name", scwin.v_mhno);
            cnd_lc_mhno.focus();
            break;

        case "9":
            scwin.mhnoFlag = "1";
            cnd_ed_hhblno.setValue(scwin.p_hblno);

            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow(0);
            }
            ds_hmhno.setCellData(ds_hmhno.getRowPosition() || 0, "code", scwin.p_docuno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition() || 0, "name", scwin.p_docuno);
            cnd_lc_mhno.focus();
            break;
    }
};

//---------------------------------------------------------
// Object Check (원본은 비어있음)
//---------------------------------------------------------
scwin.f_Check = function () {

};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    // 상태값
    scwin.f_Set("INIT");
    scwin.cfViewTab(0);
    cnd_ed_hhblno.focus();

};

//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
    // cfEnableObjects([tr_tab_center0, tr_tab_center1,tr_tab_center2]);
    scwin.cfViewTab(0);
};

//---------------------------------------------------------
// Tab Menu 선택
//---------------------------------------------------------
scwin.f_selectTabMenu = function (idx) {
    switch (idx) {
        case 0:
            scwin.tabNo = 0;
            ds_retrieve.set("tabIndex", "0");
            break;
        case 1:
            scwin.tabNo = 1;
            ds_retrieve.set("tabIndex", "1");
            break;
        case 2:
            scwin.tabNo = 2;
            ds_retrieve.set("tabIndex", "2");
            break;
    }

    scwin.cfViewTab(idx);
};

//---------------------------------------------------------
// 화면 상태 세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": //초기화
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Save, btn_Delete, btn_Update
                , btn_1, btn_3, btn_5, btn_6, btn_7, btn_8, btn_exChg, btn_cusChg
                , btn_AddRow1, btn_DelRow1, btn_DelAll1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_DelAll2, btn_CancelRow2, btn_AddRow3, btn_DelRow3, btn_DelAll3, btn_CancelRow3]);
            $c.gus.cfEnableBtnOnly([btn_7]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfEnableObjects([tbl_Search, tbl_Search2]); // 조회조건.
            scwin.statusFlag = "I";
            break;

        case "RETRIEVE":  //조회모드	
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_1, btn_exChg, btn_cusChg
                , btn_AddRow1, btn_DelRow1, btn_DelAll1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_DelAll2, btn_CancelRow2, btn_AddRow3, btn_DelRow3, btn_DelAll3, btn_CancelRow3, pu_ResultdateChange]);
            $c.gus.cfEnableBtnOnly([btn_Delete
                , btn_3, btn_5, btn_6, btn_7, btn_8]);

            scwin.f_setGridColumnsReadOnly(gr_selling, true);
            scwin.f_setGridColumnsReadOnly(gr_partner, true);
            scwin.f_setGridColumnsReadOnly(gr_buying, true);


            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }

            $c.gus.cfEnableObjects([tbl_Search, tbl_Search2]); // 조회조건.
            scwin.statusFlag = "";	 // flag null          	      
            break;

        case "CREATE": //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Delete, btn_3, btn_5, btn_6, btn_8]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel
                , btn_1, btn_7, btn_exChg, btn_cusChg
                , btn_AddRow1, btn_DelRow1, btn_DelAll1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_DelAll2, btn_CancelRow2, btn_AddRow3, btn_DelRow3, btn_DelAll3, btn_CancelRow3, pu_ResultdateChange]);

            // 그리드 수정 가능
            // gr_selling.setGridReadOnly(false);
            // gr_partner.setGridReadOnly(false);
            // gr_buying.setGridReadOnly(false);
            scwin.f_setGridColumnsReadOnly(gr_selling, false);
            scwin.f_setGridColumnsReadOnly(gr_partner, false);
            scwin.f_setGridColumnsReadOnly(gr_buying, false);

            $c.gus.cfDisableObjects([tbl_Search, tbl_Search2]); // 조회조건.     
            scwin.statusFlag = "C";
            break;

        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Delete, btn_3, btn_5, btn_6]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel
                , btn_1, btn_7, btn_exChg, btn_cusChg
                , btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2, btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3]);

            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();

            // 그리드 수정 가능
            scwin.f_setGridColumnsReadOnly(gr_selling, false);
            scwin.f_setGridColumnsReadOnly(gr_partner, false);
            scwin.f_setGridColumnsReadOnly(gr_buying, false);


            $c.gus.cfDisableObjects([tbl_Search, tbl_Search2]); // 조회조건.         		 
            scwin.statusFlag = "U";
            break;

        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update]);
            scwin.f_Set("RETRIEVE");

            break;
    }
};
//-------------------------------------------------------------------------
// PopUp 이미지 enable/disable
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {
    $c.gus.cfEnableObjects([ed_hhcurdt, ed_hheta]);
    $c.gus.cfEnableObjects([btn_popHhcnt1type, btn_popHhcnt2type, btn_popHhcnt3type, btn_popHhcnt4type, btn_hhlodcd, btn_hhdisccd, btn_hhagent, btn_hhactcust, btn_hhliner]);
};
scwin.f_DisablePopUpObj = function () {
    $c.gus.cfDisableObjects([ed_hhcurdt, ed_hheta]);
    $c.gus.cfDisableObjects([btn_popHhcnt1type, btn_popHhcnt2type, btn_popHhcnt3type, btn_popHhcnt4type, btn_hhlodcd, btn_hhdisccd, btn_hhagent, btn_hhactcust, btn_hhliner]);
};

//---------------------------------------------------------
// 조회
//---------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (cnd_ed_hhblno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);  // @은(는) 필수 입력 항목입니다.
        return;
    }
    cnd_lc_mhno.focus(); // B/L No 빠져나올때 event처리 .
    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("mhno", cnd_lc_mhno.getValue());
    ds_retrieve.set("hhio", scwin.hd_hhio);

    //실행.		       			       			       			       			    							    
    var e = await $c.sbm.execute(sbm_retrieve);

    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await scwin.sbm_retrieveF(e);
    }

    //cmd anable        	
    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(cnd_lc_mhno, true);

    ds_profit.removeAll();

    $c.sbm.execute(sbm_RetrieveProfit).then(function (e) {
        if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {

            if (ds_profit.getRowCount() > 0) {
                var rowJson = ds_profit.getRowJSON(0);

                ed_selling_total.setValue(rowJson.sellAmt); //매출
                ed_purchase_total.setValue(rowJson.pchsAmt); //매입
                ed_profit_total.setValue(rowJson.profit); //손익
                ed_profitRate_total.setValue(rowJson.profitRate); //마진율
            }
        }
    });

    // gr_selling.ColumnProp('chk', 'HeadCheck') = "False";
    // gr_partner.ColumnProp('chk', 'HeadCheck') = "False";
    // gr_buying.ColumnProp('chk', 'HeadCheck') = "False";

    gr_selling.checkAll("chk", false);
    gr_partner.checkAll("chk", false);
    gr_buying.checkAll("chk", false);

};

//---------------------------------------------------------
// 조회(하단 탭용)
//---------------------------------------------------------
scwin.f_Retrieve2 = async function () {
    // ds_houseblList.CountRow < 1 체크
    if (ds_houseblList.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["Exchange Rate Information", "하단 Search"]);
        return;
    }
    if ($c.util.isEmpty(srch_ed_hhblno.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);
        return;
    }

    cnd_lc_mhno2.focus(); // B/L No 빠져나올때 event처리 .

    // ds_retrieve 세팅
    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("mhno", cnd_lc_mhno2.getValue());
    ds_retrieve.set("hhio", scwin.hd_hhio);
    if ($c.util.isEmpty(ds_retrieve.get("tabIndex"))) {
        ds_retrieve.set("tabIndex", "0");
    }

    var idx = ds_retrieve.get("tabIndex") || "0";

    switch (idx) {
        case "0":
            if (ds_selling.getRowCount() > 0 && $c.util.isEmpty(ds_selling.getCellData(ds_selling.getRowPosition(), "tabIndex"))) {
                $c.win.alert("조회된 Selling데이터가 있습니다.\nSelling데이터를 0으로 만든 후 조회하십시오.");
            } else {
                var e = await $c.sbm.execute(sbm_retrieveSelling);

                // tr_retrieveSelling" event="OnSuccess()
                setTimeout(function () {
                    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
                        if (ds_selling.getRowCount() > 0) {
                            for (var i = 0; i < ds_selling.getRowCount(); i++) {
                                if (ds_selling.getCellData(i, "fareUnit") == ed_hhcnt1type.getValue()) {
                                    if (ed_hhcnt1.getValue() > 0) {
                                        ds_selling.setCellData(i, "chgWt", ed_hhcnt1.getValue());
                                    }
                                }
                                if (ds_selling.getCellData(i, "fareUnit") == ed_hhcnt2type.getValue()) {
                                    if (ed_hhcnt2.getValue() > 0) {
                                        ds_selling.setCellData(i, "chgWt", ed_hhcnt2.getValue());
                                    }
                                }
                                if (ds_selling.getCellData(i, "fareUnit") == ed_hhcnt3type.getValue()) {
                                    if (ed_hhcnt3.getValue() > 0) {
                                        ds_selling.setCellData(i, "chgWt", ed_hhcnt3.getValue());
                                    }
                                }
                            }
                        }
                    }
                }, 50)
            }
            break;
        case "1":
            if (ds_partner.getRowCount() > 0 && $c.util.isEmpty(ds_partner.getCellData(ds_partner.getRowPosition(), "tabIndex"))) {
                $c.win.alert("조회된 Partner데이터가 있습니다.\nPartner데이터를 0으로 만든 후 조회하십시오.");
            } else {
                var e = await $c.sbm.execute(sbm_retrievePartner);

                // tr_retrievePartner" event="OnSuccess()"
                setTimeout(function () {
                    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
                        if (ds_partner.getRowCount() > 0) {
                            for (var i = 0; i < ds_partner.getRowCount(); i++) {
                                if (ds_partner.getCellData(i, "fareUnit") == ed_hhcnt1type.getValue()) {
                                    if (ed_hhcnt1.getValue() > 0) {
                                        ds_partner.setCellData(i, "chgWt", ed_hhcnt1.getValue());
                                    }
                                }
                                if (ds_partner.getCellData(i, "fareUnit") == ed_hhcnt2type.getValue()) {
                                    if (ed_hhcnt2.getValue() > 0) {
                                        ds_partner.setCellData(i, "chgWt", ed_hhcnt2.getValue());
                                    }
                                }
                                if (ds_partner.getCellData(i, "fareUnit") == ed_hhcnt3type.getValue()) {
                                    if (ed_hhcnt3.getValue() > 0) {
                                        ds_partner.setCellData(i, "chgWt", ed_hhcnt3.getValue());
                                    }
                                }
                            }
                        }
                    }
                }, 50)
            }
            break;
        case "2":
            if (ds_buying.getRowCount() > 0 && $c.util.isEmpty(ds_buying.getCellData(ds_buying.getRowPosition(), "tabIndex"))) {
                $c.win.alert("조회된 Buying데이터가 있습니다.\nBuying데이터를 0으로 만든 후 조회하십시오.");
            } else {
                var e = await $c.sbm.execute(sbm_retrieveBuying);

                // tr_retrieveBuying" event="OnSuccess()"
                setTimeout(function () {
                    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
                        if (ds_buying.getRowCount() > 0) {
                            for (var i = 0; i < ds_buying.getRowCount(); i++) {
                                if (ds_buying.getCellData(i, "fareUnit") == ed_hhcnt1type.getValue()) {
                                    if (ed_hhcnt1.getValue() > 0) {
                                        ds_buying.setCellData(i, "chgWt", ed_hhcnt1.getValue());
                                    }
                                }
                                if (ds_buying.getCellData(i, "fareUnit") == ed_hhcnt2type.getValue()) {
                                    if (ed_hhcnt2.getValue() > 0) {
                                        ds_buying.setCellData(i, "chgWt", ed_hhcnt2.getValue());
                                    }
                                }
                                if (ds_buying.getCellData(i, "fareUnit") == ed_hhcnt3type.getValue()) {
                                    if (ed_hhcnt3.getValue() > 0) {
                                        ds_buying.setCellData(i, "chgWt", ed_hhcnt3.getValue());
                                    }
                                }
                            }
                        }
                    }
                }, 50)
            }

            break;
    }

    $c.gus.cfEnableObj(srch_ed_hhblno, true);
    $c.gus.cfEnableObj(cnd_lc_mhno2, true);
};

//---------------------------------------------------------
// 조회 조건 clear
//---------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects([cnd_ed_hhblno, cnd_ed_hhmblno]);
    ds_hmhno.removeAll();
};
//---------------------------------------------------------
// 조회 조건 지우기
//---------------------------------------------------------
scwin.f_FieldClear2 = function () {
    $c.gus.cfInitObjects([srch_ed_hhblno]);
    ds_hmhno2.removeAll();
};
//---------------------------------------------------------
// dataset 초기화
//---------------------------------------------------------
scwin.f_dataSetClear = function () {
    ds_houseblList.removeAll();
    ds_selling.removeAll();
    ds_partner.removeAll();
    ds_buying.removeAll();
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {

};
//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = async function () {
    if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;

    } else {
        scwin.f_Set("UPDATE");

        if ($c.util.isEmpty(ed_hhcur.getValue())) {
            ed_hhcur.setValue("USD");
        }


        if ($c.util.isEmpty(lc_hhexgb.getValue())) {
            lc_hhexgb.setValue(scwin.p_seaExgbIm);
        }
        if ($c.util.isEmpty(ed_hhcurdt.getValue())) {
            ed_hhcurdt.setValue(ed_hheta.getValue());
        }

    }
};

//---------------------------------------------------------
// 저장
//---------------------------------------------------------
scwin.f_Save = async function () {
    if (ds_houseblList.getModifiedIndex().length > 0 || ds_selling.getModifiedIndex().length > 0 || ds_partner.getModifiedIndex().length > 0 || ds_buying.getModifiedIndex().length > 0) {
        if (await scwin.f_validate() && await scwin.f_JobCloseYn()) {
            if (await $c.win.confirm(E_MSG_CM_CRM_001)) { //저장하시겠습니까?	
                if (scwin.statusFlag == "C") {
                    // 저장 
                    var r = ds_houseblList.getRowPosition();
                    ds_houseblList.setCellData(r, "kcomcd", scwin.hd_kcomcd);
                    ds_houseblList.setCellData(r, "hhblno", cnd_ed_hhblno.getValue());
                    ds_houseblList.setCellData(r, "mhno", cnd_lc_mhno.getValue());
                    ds_houseblList.setCellData(r, "hhio", scwin.hd_hhio);
                    ds_houseblList.setCellData(r, "inpid", scwin.userId);
                }

                scwin.v_linkcheck = "";
                // 실행 	 	
                $c.sbm.execute(sbm_save);

            }
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["House B/L Freight"]); // @은(는) 변경된 사항이 없습니다.
    }
};
//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = async function () {
    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(cnd_lc_mhno, true);

    cnd_ed_hhblno.focus();

    await scwin.f_Set("RETRIEVE");
    ds_houseblList.undoAll();
    scwin.f_cancelRow(1);
    scwin.f_cancelRow(2);
    scwin.f_cancelRow(3);
};
//-------------------------------------------------------------------------------
//  Copy 
//-------------------------------------------------------------------------------
scwin.f_Copy = function () {

};

//---------------------------------------------------------
// 삭제
//---------------------------------------------------------
scwin.f_Delete = async function () {
    if (ds_selling.getRowCount() == 0 &&
        ds_partner.getRowCount() == 0 &&
        ds_buying.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Freight Information"]);
        return;
    }

    // sbm_combo 완료 후 분기 처리 -> f_afterdelete();
    scwin.f_invoiceCheck("INVOICE_DEL");
};
scwin.f_afterDelete = async function () {
    if (scwin.invoiceCheck == "1") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
        return;
    }
    if (!(await $c.win.confirm(MSG_CM_CRM_004))) {
        return;
    }

    ds_selling.removeAll();
    ds_partner.removeAll();
    ds_buying.removeAll();

    await $c.sbm.execute(sbm_delete).then(function (rtn) {
        $c.gus.cfAlertMsg(MSG_CM_INF_004); //for=tr_delete event=OnSuccess()
        scwin.f_dataSetClear();
        scwin.f_Set("INIT");
    });
};
