scwin.f_copybuytosell2 = async function () {
    ds_selling.setRowPosition(ds_selling.getRowCount() - 1);
    var k = ds_selling.getRowCount();
    var count1 = ds_selling.getRowCount();

    //tobe추가 : asis와 데이터 동일하게 추가.
    var IL015 = [];
    for (var i = 0; i < ds_tmpCode2.getRowCount(); i++) {
        var row = ds_tmpCode2.getRowJSON(i);
        IL015.push(row.cd, row.cdNm);
    }

    for (var i = 0; i < ds_buying.getRowCount(); i++) {
        var num = -2;
        var fareEngCd = ds_buying.getCellData(i, "fareEngCd");

        for (var j = 0; j < IL015.length; j = j + 2) {
            if (IL015[j] == fareEngCd) {
                await scwin.f_addRow(1); // selling row add (기존 함수 유지)
                num = j;
                break;
            }
        }

        if (num != -2) {
            ds_selling.setCellData(k, "fareEngNm", "");
            ds_selling.setCellData(k, "fareEngCd", IL015[num + 1]);

            await scwin.f_PopUpGrid("SellingFcode", k, "T", "F");

            ds_selling.setCellData(k, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
            ds_selling.setCellData(k, "chgWt", ds_buying.getCellData(i, "chgWt"));
            ds_selling.setCellData(k, "sellUpr", ds_buying.getCellData(i, "pchsUpr"));
            ds_selling.setCellData(k, "rsltsStdDt", ds_buying.getCellData(i, "rsltsStdDt"));

            if (ds_selling.getCellData(k, "fareEngCd") == "DOC") {
                ds_selling.setCellData(k, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
            }

            var colid = "";
            var olddata = "";
            await scwin.f_sellingAmtFcrc(k, colid, olddata);
            await scwin.f_sellingAmt(k, colid, olddata);
            await scwin.f_sellingUsdAmt(k, colid, olddata);
            await scwin.f_sellingVat(k, colid, olddata);
            scwin.f_SellingSum();

            k = k + 1;
            //gr_selling.setFocusedCell(k - 1, "sellSeq");

            // tobe추가. aftereidt 안에 f_PopUpGrid 시점 안맞아서 아래와 같이 처리... 공통에서 콜백 async 처리 해줄시, 삭제.
            if (!(k == count1 + 1)) {
                await scwin.gr_selling_onafteredit(k - 1, gr_selling.getColumnIndex("bilgClntNo"), ds_selling.getCellData(k - 1, "bilgClntNo"));
            }
        }
    }
    await scwin.cfViewTab(0);
    gr_selling.setFocusedCell(k - 1, "bilgClntNo", true);
};

