scwin.f_addRow = async function (disGubun) {
    var row;
    switch (disGubun) {
        case 1: // Selling
            if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
                return;
            }
            row = ds_selling.insertRow(ds_selling.getRowCount());

            ds_selling.setCellData(row, "kcomcd", scwin.hd_kcomcd);
            ds_selling.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
            ds_selling.setCellData(row, "mhno", cnd_lc_mhno.getValue());
            ds_selling.setCellData(row, "odrNo", ds_houseblList.getCellData(0, "odrNo"));

            ds_selling.setCellData(row, "drcrCls", "D");
            ds_selling.setCellData(row, "locPtnCls", "1");
            ds_selling.setCellData(row, "mblHblCls", "H");
            ds_selling.setCellData(row, "seaAirCls", "S");
            ds_selling.setCellData(row, "ppccCls", scwin.hd_hhdanggb);
            ds_selling.setCellData(row, "inpid", scwin.userId);

            ds_selling.setCellData(row, "bilgClntNo", ed_hhactcust.getValue());
            ds_selling.setCellData(row, "bilgClntNm", txt_hhactcustnm.getValue());
            ds_selling.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
            ds_selling.setCellData(row, "exRateTyp", lc_hhexgb.getValue());

            // unit/패키지 로딩
            await scwin.f_sellingUnitLoading();
            if (ds_sellingUnit.getRowCount() > 0) {
                ds_selling.setCellData(row, "fareUnit", ds_sellingUnit.getCellData(0, "code"));
            }
            await scwin.f_packageRateSellingLoading(row, "");

            //gr_selling.focus();
            gr_selling.setFocusedCell(row, "bilgClntNo", true); // focus

            if (ds_houseblList.getCellData(0, "hhbltype") == "L") {

                ds_selling.setCellData(row, "fareUnit", "R/T");
                await scwin.f_packageRateSellingLoading(row, '');

                //gr_selling.focus();
                gr_selling.setFocusedCell(row, "bilgClntNo", true); // focus
            }
            break;
        case 2: // Partner
            if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
                return;
            }

            row = ds_partner.insertRow(ds_partner.getRowCount());

            ds_partner.setCellData(row, "kcomcd", scwin.v_kcomcd || "DBEX");
            ds_partner.setCellData(row, "drcrCls", "C");
            ds_partner.setCellData(row, "locPtnCls", "2");
            ds_partner.setCellData(row, "mblHblCls", "H");
            ds_partner.setCellData(row, "seaAirCls", "S");
            ds_partner.setCellData(row, "inpid", scwin.userId);
            await scwin.f_partnerUnitLoading();

            if (ds_partnerUnit.getRowCount() > 0) {
                ds_partner.setCellData(row, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
            }
            scwin.f_packageRatePartnerLoading(row, "");

            //gr_partner.Focus();
            gr_partner.setFocusedCell(row, "bilgClntNo"); // focus		
            break;
        case 3: // Buying
            if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
                return;
            }
            row = ds_buying.insertRow(ds_buying.getRowCount());
            ds_buying.setCellData(row, "kcomcd", scwin.v_kcomcd || "DBEX");
            ds_buying.setCellData(row, "drcrCls", "C");
            ds_buying.setCellData(row, "locPtnCls", "1");
            ds_buying.setCellData(row, "mblHblCls", "H");
            ds_buying.setCellData(row, "seaAirCls", "S");
            ds_buying.setCellData(row, "ppccCls", ""); // hd_hhpcgb
            ds_buying.setCellData(row, "inpid", scwin.userId);
            ds_buying.setCellData(row, "pchsTyp", "1");
            scwin.f_buyingUnitLoading();
            if (ds_buyingUnit.getRowCount() > 0) {
                ds_buying.setCellData(row, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
            }
            scwin.f_packageRateBuyingLoading(row, "");

            //gr_buying.Focus();
            gr_buying.setFocusedCell(row, "pchsClntNo", true);  // focus		

            if (ds_houseblList.getCellData(0, "hhbltype") == "L") {
                ds_buying.setCeLLdATA(row, "fareUnit", "R/T");
                scwin.f_packageRateBuyingLoading(row, '');
                //gr_buying.Focus();
                gr_buying.setFocusedCell(row, "pchsClntNo", true); 							// focus									
            }
            break;
    }
};

