scwin.f_addRowMulti = async function (disGubun) {
    var rowMake_selling = ed_rowMake_selling.getValue() == "" ? 1 : $c.num.parseInt(ed_rowMake_selling.getValue().trim());
    var rowMake_partner = ed_rowMake_partner.getValue() == "" ? 1 : $c.num.parseInt(ed_rowMake_partner.getValue().trim());
    var rowMake_buying = ed_rowMake_buying.getValue() == "" ? 1 : $c.num.parseInt(ed_rowMake_buying.getValue().trim());
    var row = 0;

    if (cnd_ed_hhblno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
        return;
    }

    switch (disGubun) {
        case 1:
            for (var i = 0; i < rowMake_selling; i++) {
                if (ds_selling.getRowCount() == 0 || ds_selling.getRowCount() == ds_selling.getRowPosition()) {
                    ds_selling.insertRow();
                    row = ds_selling.getRowCount() - 1;
                } else {
                    ds_selling.insertRow(ds_selling.getRowPosition() + 1);
                    row = ds_selling.getRowPosition() + 1;
                }

                ds_selling.setCellData(row, "kcomcd", scwin.hd_kcomcd);
                ds_selling.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
                ds_selling.setCellData(row, "mhno", cnd_lc_mhno.getValue());
                ds_selling.setCellData(row, "odrNo", ds_houseblList.getCellData(0, "odrNo"));

                ds_selling.setCellData(row, "drcrCls", "D");
                ds_selling.setCellData(row, "locPtnCls", "1");
                ds_selling.setCellData(row, "mblHblCls", "H");
                ds_selling.setCellData(row, "seaAirCls", "S");
                ds_selling.setCellData(row, "ppccCls", scwin.hd_hhdanggb);
                ds_selling.setCellData(row, "inpid", scwin.userId);

                ds_selling.setCellData(row, "bilgClntNo", ed_hhactcust.getValue());
                ds_selling.setCellData(row, "bilgClntNm", txt_hhactcustnm.getValue());
                ds_selling.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
                ds_selling.setCellData(row, "exRateTyp", lc_hhexgb.getValue());

                // unit/패키지 로딩
                await scwin.f_sellingUnitLoading();

                ds_selling.setCellData(row, "fareUnit", ds_sellingUnit.getCellData(0, "code"));

                if (ds_houseblList.getCellData(0, "hhbltype") == "L") {
                    ds_selling.setCellData(row, "fareUnit", "R/T");
                }

                await scwin.f_packageRateSellingLoading(row, '');
            }
            gr_selling.setFocusedCell(row, "bilgClntNo", true); // focus
            break;
        case 2: // Partner
            for (var i = 0; i < rowMake_partner; i++) {
                if (ds_partner.getRowCount() == 0 || ds_partner.getRowCount() == ds_partner.getRowPosition()) {
                    ds_partner.insertRow();
                    row = ds_partner.getRowPosition();
                } else {
                    ds_partner.insertRow(ds_partner.getRowPosition() + 1);
                    row = ds_partner.getRowPosition() + 1;
                }

                ds_partner.setCellData(row, "kcomcd", scwin.hd_kcomcd);
                ds_partner.setCellData(row, "blNo", cnd_ed_hhblno.getValue()); //update일때.
                ds_partner.setCellData(row, "mhno", cnd_lc_mhno.getValue()); //update일때.
                ds_partner.setCellData(row, "odrNo", ds_houseblList.getCellData(0, "odrNo"));
                ds_partner.setCellData(row, "drcrCls", "C"); //D/C					
                ds_partner.setCellData(row, "locPtnCls", "2"); //국내 : 1, 해외 :2 	
                ds_partner.setCellData(row, "mblHblCls", "H"); //house/master
                ds_partner.setCellData(row, "seaAirCls", "S"); // sea/air	
                ds_partner.setCellData(row, "ppccCls", scwin.hd_hhpcgb);  	//pp/cc			
                ds_partner.setCellData(row, "inpid", scwin.userId);

                ds_partner.setCellData(row, "bilgClntNo", ed_hhagent.getValue());
                ds_partner.setCellData(row, "bilgClntNm", txt_hhagentnm.getValue());   //partner name								
                ds_partner.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);   //실적일	
                ds_partner.setCellData(row, "exRateTyp", lc_hhexgb.getValue());  //exgb				
                //unit처리.
                await scwin.f_partnerUnitLoading();
                ds_partner.setCellData(row, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
                await scwin.f_packageRatePartnerLoading(row, '');

            }
            gr_partner.setFocusedCell(row, "bilgClntNo"); // focus
            break;
        case 3: // Buying
            for (var i = 0; i < rowMake_buying; i++) {
                if (ds_buying.getRowCount() == 0 || ds_buying.getRowCount() == ds_buying.getRowPosition()) {
                    ds_buying.insertRow();
                    row = ds_buying.getRowPosition();
                } else {
                    ds_buying.insertRow(ds_buying.getRowPosition() + 1);
                    row = ds_buying.getRowPosition() + 1;
                }

                ds_buying.setCellData(row, "kcomcd", scwin.hd_kcomcd);
                ds_buying.setCellData(row, "blNo", cnd_ed_hhblno.getValue()); //update일때.
                ds_buying.setCellData(row, "mhno", cnd_lc_mhno.getValue()); //update일때.
                ds_buying.setCellData(row, "odrNo", ds_houseblList.getCellData(0, "odrNo"));
                ds_buying.setCellData(row, "drcrCls", "C"); // DR/CR
                ds_buying.setCellData(row, "locPtnCls", "1"); //국내 : 1, 해외 :2 			
                ds_buying.setCellData(row, "mblHblCls", "H"); //house/master	
                ds_buying.setCellData(row, "seaAirCls", "S"); // sea/air
                ds_buying.setCellData(row, "ppccCls", scwin.hd_hhpcgb);  		//pp/cc																	
                ds_buying.setCellData(row, "inpid", scwin.userId);

                ds_buying.setCellData(row, "pchsClntNo", ed_hhliner.getValue());
                ds_buying.setCellData(row, "pchsClntNm", txt_hhlinernm.getValue());   //Liner name					
                ds_buying.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);  	//실적일	
                ds_buying.setCellData(row, "exRateTyp", lc_hhexgb.getValue());  	//exgb					
                ds_buying.setCellData(row, "pchsTyp", "1");

                ds_buying.setCellData(row, "crcCd", ds_buying.getCellData(row - 1, "crcCd"));

                //unit처리.
                await scwin.f_buyingUnitLoading();
                ds_buying.setCellData(row, "fareUnit", ds_buyingUnit.getCellData(0, "code"));

                if (ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhbltype") == "L") {
                    ds_buying.setCellData(row, "fareUnit", "R/T");
                }
                await scwin.f_packageRateBuyingLoading(row, '');

            }
            gr_buying.setFocusedCell(row, "pchsClntNo"); // focus
            break;
    }

    // TOBE추가
    // scwin.f_Set("CREATE");
};

