scwin.f_deleteRow = async function (disGubun) {
    var tmp = "";
    var tmpRowPosition = -1;
    var removeR = [];
    var deleteR = []
    var addRowState = "";

    switch (disGubun) {
        case 1:  	//Selling
            tmp = ds_selling
            tmpRowPosition = tmp.getRowPosition();
            for (var i = 0; i < tmp.getRowCount(); i++) {
                addRowState = tmp.getRowStatus(i);
                if (tmp.getCellData(i, "chk") == "T" || i == tmpRowPosition) {
                    if (tmp.getCellData(i, "certiNo") == "") {
                        if (addRowState == "C") {
                            removeR.push(i);
                        } else {
                            deleteR.push(i);
                        }


                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                        return;
                    }
                }
            }
            break;

        case 2:  	// Partner
            tmp = ds_partner;
            tmpRowPosition = tmp.getRowPosition();
            for (var i = 0; i < tmp.getRowCount(); i++) {
                addRowState = tmp.getRowStatus(i);
                if (tmp.getCellData(i, "chk") == "T" || i == tmpRowPosition) {
                    if (ds_partner.getCellData(i, "certiNo") == "") {
                        if (addRowState == "C") {
                            removeR.push(i);
                        } else {
                            deleteR.push(i);
                        }
                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                        return;
                    }
                }
            }
            break;

        case 3:  	// Buying
            tmp = ds_buying;
            tmpRowPosition = tmp.getRowPosition();
            for (var i = 0; i < tmp.getRowCount(); i++) {
                addRowState = tmp.getRowStatus(i);
                if (tmp.getCellData(i, "chk") == "T" || i == tmpRowPosition) {
                    if (tmp.getCellData(i, "pchsCertiNo") == "") {
                        if (tmp.getCellData(i, "dcsnClsCd") == "확정") {
                            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["확정", "delete"]);  // @은(는) @할 수 없습니다.
                            return;
                        } else {
                            if (addRowState == "C") {
                                removeR.push(i);
                            } else {
                                deleteR.push(i);
                            }
                        }
                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                        return false;
                    }
                }
            }
            break;

        default:
            break;
    }

    if (removeR.length != 0) {
        tmp.removeRows(removeR);
    }

    if (deleteR.length != 0) {
        tmp.undoRow(tmpRowPosition);
        tmp.deleteRows(deleteR);
    }
};
