//---------------------------------------------------------
// 취소(Undo)
//---------------------------------------------------------
scwin.f_cancelRow = function (disGubun) {
    var ds;
    var tabIndex;
    switch (disGubun) {
        case 1: ds = ds_selling; tabIndex = "0"; break;
        case 2: ds = ds_partner; tabIndex = "1"; break;
        case 3: ds = ds_buying; tabIndex = "2"; break;
    }
    if (!ds || ds.getRowCount() == 0) return;
    if (ds.getCellData(0, "tabIndex") == tabIndex) {
        ds.removeAll();
    } else {
        ds.undoAll();

        //tobe추가 : 행추가해서 생긴 행은 취소하면 화면에서 삭제됨.
        creatRow = ds.getRowIndexByStatus("C");
        ds.removeRows(creatRow);

    }
};
scwin.f_cancelRow1 = function () {
    scwin.f_cancelRow(1);
}
scwin.f_cancelRow2 = function () {
    scwin.f_cancelRow(2);
