scwin.f_validate = async function () {
    if (!$c.gus.cfValidate([ed_hhcurdt, ed_hheta])) {  //validExp 가 yes일때 check
        return false;
    }

    var vaildArray = [
        { id: "rsltsStdDt", name: "Result", mandatory: true, valid: "date", format: "YYYYMMDD" }
    ]

    if (!await $c.gus.cfValidateGrid(gr_selling, null, null, vaildArray, "Selling")) {
        return false;
    }

    if (!await $c.gus.cfValidateGrid(gr_partner, null, null, vaildArray, "Partner")) {
        return false;
    }

    if (!await $c.gus.cfValidateGrid(gr_buying, null, null, vaildArray, "Buying")) {
        return false;
    }

    if ($c.util.isEmpty(ed_hhcur.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]); //@는 필수입력항목입니다.		
        ed_hhcur.focus();
        return false;
    }
    if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House B/L"]); //@는 필수입력항목입니다.		
        cnd_ed_hhblno.focus();
        return false;
    }
    if ($c.util.isEmpty(ed_hheta.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETA"]); //@는 필수입력항목입니다.		
        ed_hheta.focus();
        return false;
    }

    // Container Type value check
    var cntTypeEdits = [ed_hhcnt1type, ed_hhcnt2type, ed_hhcnt3type, ed_hhcnt4type];
    for (var ed of cntTypeEdits) {
        var v = ed.getValue();
        if (!$c.util.isEmpty(v)) {
            var tmp = ds_containerType.getMatchedColumnData("code", v, "code");
            if (!tmp || tmp.length <= 0) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
                ed.focus();
                return false;
            }
        }
    }

    // Selling
    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if ($c.util.isEmpty(ds_selling.getCellData(i, "bilgClntNm"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]); //@는 필수입력항목입니다.
            //gr_selling.focus();
            gr_selling.setFocusedCell(i, "bilgClntNm", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_selling.getCellData(i, "fareEngCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]); //@는 필수입력항목입니다.
            //gr_selling.focus();
            gr_selling.setFocusedCell(i, "fareEngCd", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_selling.getCellData(i, "crcCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]); //@는 필수입력항목입니다.
            //gr_selling.focus();
            gr_selling.setFocusedCell(i, "crcCd", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_selling.getCellData(i, "fareUnit"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]); //@는 필수입력항목입니다.
            //gr_selling.focus();
            gr_selling.setFocusedCell(i, "fareUnit", true);  // mccntno
            return false;
        }
    }

    // Partner
    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if ($c.util.isEmpty(ds_partner.getCellData(i, "bilgClntNo"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]); //@는 필수입력항목입니다.
            //gr_partner.focus();
            gr_partner.setFocusedCell(i, "bilgClntNo", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_partner.getCellData(i, "bilgClntNm"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]); //@는 필수입력항목입니다.
            //gr_partner.focus();
            gr_partner.setFocusedCell(i, "bilgClntNm", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_partner.getCellData(i, "fareEngCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]); //@는 필수입력항목입니다.
            //gr_partner.focus();
            gr_partner.setFocusedCell(i, "fareEngCd", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_partner.getCellData(i, "drcrCls"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["D/C"]); //@는 필수입력항목입니다.
            //gr_partner.focus();
            gr_partner.setFocusedCell(i, "drcrCls", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_partner.getCellData(i, "crcCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]); //@는 필수입력항목입니다.
            //gr_partner.focus();
            gr_partner.setFocusedCell(i, "crcCd", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_partner.getCellData(i, "fareUnit"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]); //@는 필수입력항목입니다.
            //gr_partner.focus();
            gr_partner.setFocusedCell(i, "fareUnit", true);  // mccntno
            return false;
        }
    }

    // Buying
    for (var i = 0; i < ds_buying.getRowCount(); i++) {
        if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsTyp"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Type"]); //@는 필수입력항목입니다.
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "pchsTyp", true);  // mccntno
            return false;
        }

        if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsClntNo"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]); //@는 필수입력항목입니다.
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "pchsClntNo", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsClntNm"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]); //@는 필수입력항목입니다.
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "pchsClntNm", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "fareEngCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]); //@는 필수입력항목입니다.
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "fareEngCd", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "crcCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]); //@는 필수입력항목입니다.
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "crcCd", true);  // mccntno
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "fareUnit"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]); //@는 필수입력항목입니다.
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "fareUnit", true);  // mccntno
            return false;
        }
        if (ds_buying.getCellData(i, "pchsTyp") == "3" && $c.util.isEmpty(ds_buying.getCellData(i, "sellDeptCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Inner Department"]); //@는 필수입력항목입니다.
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "sellDeptCd", true);  // mccntno
            return false;
        }
    }

    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "vatYn") == 0 && ds_selling.getCellData(i, "vatAmt") > 0) {
            await $c.win.alert("영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
            //gr_selling.focus();
            gr_selling.setFocusedCell(i, "vatAmt", true);
            return false;
        }

        if (ds_selling.getCellData(i, "vatYn") == 1) {
            if (Math.abs(Math.round(ds_selling.getCellData(i, "sellAmt") * 0.1) - ds_selling.getCellData(i, "vatAmt")) > 1) {
                await $c.win.alert("VAT 금액은 Amount(W)금액의 10%입니다. \nSelling List " + (i + 1) + "번째 금액을 확인하세요.");
                //gr_selling.focus();
                gr_selling.setFocusedCell(i, "vatAmt", true);
                return false;
            }

            if (ds_selling.getCellData(i, "sellAmt") == "0") {
                await $c.win.alert("Amount(W) 금액이 0입니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
                //gr_selling.focus();
                gr_selling.setFocusedCell(i, "sellAmt", true);
                return false;
            }
        }



        //삭제 시 내부거래 체크
        if (ds_selling.getRowStatus(i) == "D") { // == "2"
            await scwin.f_postDtChk(ds_selling.getCellData(i, "odrNo"), ds_selling.getCellData(i, "sellSeq"), ds_selling.getCellData(i, "kcomcd")
                , ds_selling.getCellData(i, "seaAirCls"), ds_selling.getCellData(i, "blNo"), ds_selling.getCellData(i, "mhno"));
            var isPostDt = ds_PostDtDataSet.getCellData(0, "col1");

            if (!$c.util.isEmpty(isPostDt)) {
                await $c.win.alert("내부거래 확정 건 입니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
                return false;
            }
        }
    }

    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "sellAmt") == "0") {
            await $c.win.alert("Amount(W) 금액이 0입니다. \nPartner List " + (i + 1) + "번째 데이터를 확인하세요.");
            //gr_partner.focus();
            gr_partner.setFocusedCell(i, "sellAmt", true);
            return false;
        }

        //삭제 시 내부거래 체크
        if (ds_partner.getRowStatus(i) == "D") { // == "2"
            await scwin.f_postDtChk(ds_partner.getCellData(i, "odrNo"), ds_partner.getCellData(i, "sellSeq"), ds_partner.getCellData(i, "kcomcd")
                , ds_partner.getCellData(i, "seaAirCls"), ds_partner.getCellData(i, "blNo"), ds_partner.getCellData(i, "mhno"));
            var isPostDt = ds_PostDtDataSet.getCellData(0, "col1");

            if (!$c.util.isEmpty(isPostDt)) {
                await $c.win.alert("내부거래 확정 건 입니다. \nPartner List " + (i + 1) + "번째 데이터를 확인하세요.");
                return false;
            }
        }
    }

    for (var i = 0; i < ds_buying.getRowCount(); i++) {
        if (ds_buying.getCellData(i, "vatYn") == 0 && ds_buying.getCellData(i, "vat") > 0) {
            await $c.win.alert("영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nBuying List " + (i + 1) + "번째 데이터를 확인하세요.");
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "vat", true);
            return false;
        }

        if (ds_buying.getCellData(i, "pchsAmt") == "0") {
            await $c.win.alert("Amount(W) 금액이 0입니다. \nBuying List " + (i + 1) + "번째 데이터를 확인하세요.");
            //gr_buying.focus();
            gr_buying.setFocusedCell(i, "pchsAmt", true);
            return false;
        }

        //삭제 시 내부거래 체크
        if (ds_buying.getRowStatus(i) == "D") { // == "2"
            await scwin.f_postDtChk(ds_buying.getCellData(i, "odrNo"), ds_buying.getCellData(i, "pchsSeq"), ds_buying.getCellData(i, "kcomcd")
                , ds_buying.getCellData(i, "seaAirCls"), ds_buying.getCellData(i, "blNo"), ds_buying.getCellData(i, "mhno"));
            var isPostDt = ds_PostDtDataSet.getCellData(0, "col1");

            if (!$c.util.isEmpty(isPostDt)) {
                await $c.win.alert("내부거래 확정 건 입니다. \nbuying List " + (i + 1) + "번째 데이터를 확인하세요.");
                return false;
            }
        }
    }

    return true;
};
