//-------------------------------------------------------------------------
// MHNO 가져오기
//-------------------------------------------------------------------------
scwin.f_MhnoLoading = function (gubun) {
    var blno = "";
    if (gubun == "1") {
        blno = cnd_ed_hhblno.getValue();
        if (!$c.util.isEmpty(blno)) {
            scwin._comboTarget = "HMHNO1";
            scwin.f_commCode("ilCommonEBC", "retriveSeaHouseMhnoListCombo", blno);
        } else {
            ds_hmhno.removeAll();
            cnd_lc_mhno.setValue("");
        }
        return;
    } else if (gubun == "2") {
        blno = srch_ed_hhblno.getValue();
        if (!$c.util.isEmpty(blno)) {
            scwin._comboTarget = "HMHNO2";
            scwin.f_commCode("ilCommonEBC", "retriveSeaHouseMhnoListCombo", blno);
        } else {
            ds_hmhno2.removeAll();
            cnd_lc_mhno2.setValue("");
        }
    }
};
