//---------------------------------------------------------
// Selling/Partner/Buying 환율 조회
//---------------------------------------------------------
scwin.f_ExRateSellingGridLoading = function () {
    scwin.f_loadExRateGrid(ds_selling, "SELLING");
};
scwin.f_ExRatePartnerGridLoading = function () {
    scwin.f_loadExRateGrid(ds_partner, "PARTNER");
};
scwin.f_ExRateBuyingGridLoading = function () {
    scwin.f_loadExRateGrid(ds_buying, "BUYING");
};
//-------------------------------------------------------------------------
// ExRate Grid 공통 (Selling/Buying/Partner)
//-------------------------------------------------------------------------
scwin.f_loadExRateGrid = function (ds, target) {
    var rp = ds.getRowPosition();

    var houseCur = ed_hhcur.getValue();
    var rowCur = ds.getCellData(rp, "crcCd");

    if (houseCur == rowCur) {
        ds.setCellData(rp, "exRate", ed_hhexrate.getValue());
        return;
    }

    // 이미 환율이 있으면 조회 불필요
    var exRate = ds.getCellData(rp, "exRate");
    if (exRate != "" && exRate != "0") return;

    var param1 = rowCur;
    var param2 = ed_hhcurdt.getValue();
    var param3 = lc_hhexgb.getValue();

    scwin._comboTarget = target; // "SELLING" | "BUYING" | "PARTNER"
    scwin._exRateRow = rp;
    scwin._exRateCur = param1;

    scwin.f_commCode("ilCommonEBC", "retrieveExRate", param1, param2, param3);
};
//---------------------------------------------------------
// Unit 로딩
//---------------------------------------------------------
//-------------------------------------------------------------------------
// 컨테이너 타입/수량 기반 param1~4 만들기 공통
//-------------------------------------------------------------------------
scwin._getCntParams = function () {
    var cnt = ["0", "0", "0", "0"];
    var typeComp = [ed_hhcnt1type, ed_hhcnt2type, ed_hhcnt3type, ed_hhcnt4type];
    var qtyComp = [ed_hhcnt1, ed_hhcnt2, ed_hhcnt3, ed_hhcnt4];

    for (var i = 0; i < 4; i++) {
        var t = typeComp[i] ? String(typeComp[i].getValue() || "").trim() : "";
        var q = qtyComp[i] ? String(qtyComp[i].getValue() || "").trim() : "";

        if (t != "" && q != "" && q != "0") {
            cnt[i] = t;
        }
    }
    return cnt; // [cnt1,cnt2,cnt3,cnt4]
};
//-------------------------------------------------------------------------
// Unit 조회 공통 (Selling/Partner/Buying)
//-------------------------------------------------------------------------
scwin.f_sellingUnitLoading = async function () {
    var cnt = scwin._getCntParams();
    await scwin.f_commCodeSync("SeaImportHouseEBC", "retriveUnitList", cnt[0], cnt[1], cnt[2], cnt[3]);
    ds_sellingUnit.setJSON(ds_tmpCode.getAllJSON(), false);
};
scwin.f_partnerUnitLoading = async function () {
    var cnt = scwin._getCntParams();
    await scwin.f_commCodeSync("SeaImportHouseEBC", "retriveUnitList", cnt[0], cnt[1], cnt[2], cnt[3]);
    ds_partnerUnit.setJSON(ds_tmpCode.getAllJSON(), false);
};
scwin.f_buyingUnitLoading = async function () {
