//-------------------------------------------------------------------------
//Ex-rate Change 가져오기
//------------------------------------------------------------------------- 	
scwin.f_exRateChange = async function () {
    if (scwin.tabNo == 0) { // Selling
        if (ds_selling.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Selling Information"]);
            return;
        }

        if (await $c.win.confirm(MSG_CM_CRM_001)) {
            for (var i = 0; i < ds_selling.getRowCount(); i++) {
                if ($c.util.isEmpty(ds_selling.getCellData(i, "certiNo")) && ds_selling.getCellData(i, "crcCd") == ed_hhcur.getValue()) {
                    ds_selling.setCellData(i, "exRate", ed_hhexrate.getValue());
                    scwin.f_sellingAmt(i, "", "");
                    scwin.f_sellingVat(i, "", "");
                    scwin.f_sellingUsdAmt(i, "", "");
                }
            }
        }
    } else if (scwin.tabNo == 1) { // Partner
        if (ds_partner.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Partner Information"]);
            return;
        }

        if (await $c.win.confirm(MSG_CM_CRM_001)) {
            for (var i = 0; i < ds_partner.getRowCount(); i++) {
                if ($c.util.isEmpty(ds_partner.getCellData(i, "certiNo")) && ds_partner.getCellData(i, "crcCd") == ed_hhcur.getValue()) {
                    ds_partner.setCellData(i, "exRate", ed_hhexrate.getValue());
                    scwin.f_partnerAmt(i, "", "");
                    scwin.f_partnerUsdAmt(i, "", "");
                }
            }
        }
    } else if (scwin.tabNo == 2) { // Buying
        if (!ds_buying || ds_buying.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Buying Information"]);
            return;
        }

        if (await $c.win.confirm(E_MSG_CM_CRM_001)) {
            for (var i = 0; i < ds_buying.getRowCount(); i++) {
                if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsCertiNo")) && ds_buying.getCellData(i, "crcCd") == ed_hhcur.getValue()) {
                    ds_buying.setCellData(i, "exRate", ed_hhexrate.getValue());
                    scwin.f_buyingAmt(i, "", "");
                    scwin.f_buyingVat(i, "", "");
                    scwin.f_buyingUsdAmt(i, "", "");
                }
            }
        }
    }
};

//---------------------------------------------------------
// Customer Change (팝업)
//---------------------------------------------------------
scwin.f_CustomerChange = async function () {
    // 팝업 옵션
    var opt = {
        width: "460",
        height: "280",
        id: "popCustomerChange",
        popupName: "CustomerChange",
        title: "Customer Change",
        callbackFn: "scwin.f_CustomerChange_callback"
    }
    // 팝업으로 넘길 데이터(필요시)
    var data = {};
    var url = "/ui/il/common/xml/ilCommonCustomerChange.xml";

    var rtnList = await $c.win.openPopup(url, opt, data);


    if (typeof (rtnList) != "undefined") {
        if (rtnList[0] == "N/A") {
            if (scwin.tabNo == 0) { // Selling 
                //			var ds_selling = ds_SellingFreightInfo;
                if (ds_selling.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Selling Information"]); //  @이(가) 존재하지 않습니다.		
                } else {
                    var check = await $c.win.confirm(E_MSG_CM_CRM_001);
                    if (check) { //저장하시겠습니까?	
                        for (var i = 0; i < ds_selling.getRowCount(); i++) {
                            if (ds_selling.getCellData(i, "certiNo").trim() == "") {
                                if (ds_selling.getCellData(i, "bilgClntNo") == rtnList[1]) {
                                    ds_selling.setCellData(i, "bilgClntNo", rtnList[3]);
                                    ds_selling.setCellData(i, "bilgClntNm", rtnList[4]);
                                }

                            }
                        }
                    }
                }
            } else if (scwin.tabNo == 1) { //partner
                //			var ds_partner = ds_PartnerFreightInfo;
                if (ds_partner.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Partner Information"]); //  @이(가) 존재하지 않습니다.	
                } else {
                    var check = await $c.win.confirm(E_MSG_CM_CRM_001);
                    if (check) { //저장하시겠습니까?	
                        for (var i = 0; i < ds_partner.getRowCount(); i++) {
                            if (ds_partner.getCellData(i, "certiNo").trim() == "") {
                                if (ds_partner.getCellData(i, "bilgClntNo") == rtnList[1]) {
                                    ds_partner.setCellData(i, "bilgClntNo", rtnList[3]);
                                    ds_partner.setCellData(i, "bilgClntNm", rtnList[4]);
                                }
                            }
                        }
                    }
                }
            } else if (scwin.tabNo == 2) { // Buying 
                //			var ds_buying = ds_BuyingFreightInfo;
                if (ds_buying.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Buying Information"]); //  @이(가) 존재하지 않습니다.	
                } else {
                    var check = await $c.win.confirm(E_MSG_CM_CRM_001);
                    if (check) { //저장하시겠습니까?	
                        for (var i = 0; i < ds_buying.getRowCount(); i++) {
                            if (ds_buying.getCellData(i, "pchsCertiNo").trim() == "") {

                                if (ds_buying.getCellData(i, "pchsClntNo") == rtnList[1]) {
                                    ds_buying.setCellData(i, "pchsClntNo", rtnList[3]);
                                    ds_buying.setCellData(i, "pchsClntNm", rtnList[4]);
                                }
                            }
                        }
                    }
                }
            }
        }
    }
};

scwin.f_CustomerChange_callback = async function (rtnList) {
    if (!rtnList || rtnList[0] != "N/A") {
        return;
    }

    var oldCode = rtnList[1] || "";
    var newCode = rtnList[3] || "";
    var newName = rtnList[4] || "";

    if (scwin.tabNo == 0) { // Selling
        if (ds_selling.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Selling Information"]);
            return;
        }

        if (!(await $c.win.confirm(E_MSG_CM_CRM_001))) {
            return;
        }

        for (var i = 0; i < ds_selling.getRowCount(); i++) {
            if ($c.util.isEmpty(ds_selling.getCellData(i, "certiNo")) && ds_selling.getCellData(i, "bilgClntNo") == oldCode) {
                ds_selling.setCellData(i, "bilgClntNo", newCode);
                ds_selling.setCellData(i, "bilgClntNm", newName);
            }
        }
    } else if (tabNo == "1") { // Partner
        if (ds_partner.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Partner Information"]);
            return;
        }

        if (!(await $c.win.confirm(E_MSG_CM_CRM_001))) {
            return;
        }

        for (var i = 0; i < ds_partner.getRowCount(); i++) {
            if ($c.util.isEmpty(ds_partner.getCellData(i, "certiNo")) && ds_partner.getCellData(i, "bilgClntNo") == oldCode) {
                ds_partner.setCellData(i, "bilgClntNo", newCode);
                ds_partner.setCellData(i, "bilgClntNm", newName);
            }
        }
    } else if (tabNo == "2") { // Buying
        if (ds_buying.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Buying Information"]);
            return;
        }

        if (!(await $c.win.confirm(E_MSG_CM_CRM_001))) {
            return;
        }

        for (var i = 0; i < ds_buying.getRowCount(); i++) {
            if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsCertiNo")) && ds_buying.getCellData(i, "pchsClntNo") == oldCode) {
                ds_buying.setCellData(i, "pchsClntNo", newCode);
                ds_buying.setCellData(i, "pchsClntNm", newName);
            }
        }
    } // end if 
}
