scwin._f_packageRateLoading = function (ds, row, colid) {
    var v_wgt = Number(ed_hhgwgt.getValue()) / 1000;
    var v_msr = Number(ed_hhmsr.getValue());
    var v_wgtR = Math.ceil(v_wgt);
    var v_msrR = Math.ceil(v_msr);
    var wgt = 0;
    var msr = 0;
    var r = row; // ds.getRowPosition();
    if (ds.getCellData(r, "fareEngCd") == "WFG") {
        wgt = v_wgtR;
        msr = v_msrR;
    } else {
        wgt = v_wgt;
        msr = v_msr;
    }

    if (ds.getCellData(r, "fareUnit") == "WGT" || ds.getCellData(r, "fareUnit") == "M/T") {
        //ds.NameValue(ds_partner.RowPosition,"chgWt") = ed_hhgwgt.getValue();
        if (ds.getCellData(r, "fareEngCd") == "WFG") {
            ds.setCellData(r, "chgWt", Math.ceil(Number(ed_hhgwgt.getValue())));
        } else {
            ds.setCellData(r, "chgWt", ed_hhgwgt.getValue());
        }
    } else if (ds.getCellData(r, "fareUnit") == "R/T") {
        if (v_wgt > v_msr) {
            ds.setCellData(r, "chgWt", wgt);
        } else {
            ds.setCellData(r, "chgWt", msr);
        }
    } else if (ds.getCellData(r, "fareUnit") == "CBM") {
        ds.setCellData(r, "chgWt", msr);
    } else if (ds.getCellData(r, "fareUnit") == "CASE") {
        ds.setCellData(r, "chgWt", "1");
    } else {
        if (ds.getCellData(r, "fareUnit") == ed_hhcnt1type.getValue()) {
            ds.setCellData(r, "chgWt", ed_hhcnt1.getValue());
        } else if (ds.getCellData(r, "fareUnit") == ed_hhcnt2type.getValue()) {
            ds.setCellData(r, "chgWt", ed_hhcnt2.getValue());
        } else if (ds.getCellData(r, "fareUnit") == ed_hhcnt3type.getValue()) {
            ds.setCellData(r, "chgWt", ed_hhcnt3.getValue());
        } else if (ds.getCellData(r, "fareUnit") == ed_hhcnt4type.getValue()) {
            ds.setCellData(r, "chgWt", ed_hhcnt4.getValue());
        }
    }
}
