//---------------------------------------------------------
// 합계 계산
//---------------------------------------------------------
scwin.f_SellingSum = function () {
    var checked = 0;
    var v_SellingSumAmount = 0;
    var v_SellingSumAmountW = 0;
    var v_SellingSumVat = 0;
    var v_SellingSumAmountUs = 0;
    var v_SellingAmountSum = 0;
    var v_SellingSumKrw = 0;
    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getRowStatus(i) != "D") {
            var amtF = Number(ds_selling.getCellData(i, "sellAmtFcrc") || 0);
            var amtW = Number(ds_selling.getCellData(i, "sellAmt") || 0);
            var vat = Number(ds_selling.getCellData(i, "vatAmt") || 0);
            var usd = Number(ds_selling.getCellData(i, "usdAmt") || 0);
            var crc = ds_selling.getCellData(i, "crcCd");


            v_SellingSumAmount = v_SellingSumAmount + amtF
            v_SellingSumAmountW = v_SellingSumAmountW + amtW
            v_SellingSumVat = v_SellingSumVat + vat
            v_SellingSumAmountUs = v_SellingSumAmountUs + usd


            if (crc == "KRW") {
                v_SellingSumKrw = v_SellingSumKrw + amtW;
                v_SellingSumKrw = v_SellingSumKrw + vat;
            }
        }
        checked++;
    }
    ed_SellingSumAmount.setValue(v_SellingSumAmount);
    ed_SellingSumAmountW.setValue(v_SellingSumAmountW);
    ed_SellingSumVat.setValue(v_SellingSumVat);

    v_SellingAmountSum = v_SellingSumAmountW + v_SellingSumVat;
    ed_SellingAmountSum.setValue(v_SellingAmountSum);
};
//-------------------------------------------------------------------------
//Partner sum
//------------------------------------------------------------------------- 
scwin.f_PartnerSum = function () {
    var rc = ds_partner.getRowCount();
    var v_PartnerSumAmount = 0;
    var v_PartnerSumAmountW = 0;
    var v_PartnerSumAmountUs = 0;
    var v_PartnerSumKrw = 0;
    for (var i = 0; i < rc; i++) {
        var amtF = Number(ds_partner.getCellData(i, "sellAmtFcrc") || 0);
        var amtW = Number(ds_partner.getCellData(i, "sellAmt") || 0);
        var usd = Number(ds_partner.getCellData(i, "usdAmt") || 0);
        var crc = ds_partner.getCellData(i, "crcCd");
        v_PartnerSumAmount += amtF;
        v_PartnerSumAmountW += amtW;
        v_PartnerSumAmountUs += usd;
        if (crc == "KRW") {
            v_PartnerSumKrw += amtW;
        }
    }
    ed_PartnerSumAmount.setValue(v_PartnerSumAmount);
    ed_PartnerSumAmountW.setValue(v_PartnerSumAmountW);
};
//-------------------------------------------------------------------------
//Buying sum
//------------------------------------------------------------------------- 
scwin.f_BuyingSum = function () {
    var rc = ds_buying.getRowCount();
    var v_BuyingSumAmount = 0;
    var v_BuyingSumAmountW = 0;
    var v_BuyingSumVat = 0;
    var v_BuyingSumAmountUs = 0;
    var v_BuyingAmountSum = 0;
    var v_BuyingSumKrw = 0;
    for (var i = 0; i < rc; i++) {
        var amtF = Number(ds_buying.getCellData(i, "pchsAmtFcrc") || 0);
        var amtW = Number(ds_buying.getCellData(i, "pchsAmt") || 0);
        var vat = Number(ds_buying.getCellData(i, "vat") || 0);
        var usd = Number(ds_buying.getCellData(i, "usdAmt") || 0);
        var crc = ds_buying.getCellData(i, "crcCd");
        v_BuyingSumAmount += amtF;
        v_BuyingSumAmountW += amtW;
        v_BuyingSumVat += vat;
        v_BuyingSumAmountUs += usd;
        if (crc == "KRW") {
            v_BuyingSumKrw += (amtW + vat);
        }
    }
    ed_BuyingSumAmount.setValue(v_BuyingSumAmount);
    ed_BuyingSumAmountW.setValue(v_BuyingSumAmountW);
    ed_BuyingSumVat.setValue(v_BuyingSumVat);

    v_BuyingAmountSum = v_BuyingSumAmountW + v_BuyingSumVat;
    ed_BuyingAmountSum.setValue(v_BuyingAmountSum);
};

