//-------------------------------------------------------------------------
//tab List의 값을 ds_houseblList의 컬럼으로 변경한다. (gubun, dataSet)
//0 : selling, 1 : partner, 2 : buying
//-------------------------------------------------------------------------
scwin.f_chgGridColumnToHouseBlDs = async function (gubun, ds) {
    for (var i = 0; i < ds.getRowCount(); i++) {
        ds.setCellData(i, "kcomcd", scwin.hd_kcomcd);
        ds.setCellData(i, "blNo", cnd_ed_hhblno.getValue()); //update일때.
        ds.setCellData(i, "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds.setCellData(i, "odrNo", ds_houseblList.getCellData(0, "odrNo"));

        ds.setCellData(i, "mblHblCls", "H"); //house/master       
        ds.setCellData(i, "seaAirCls", "S"); // sea/air
        ds.setCellData(i, "ppccCls", scwin.hd_hhpcgb);      //pp/cc                                         
        ds.setCellData(i, "inpid", scwin.userId);

        if (gubun == "0") {
            ds.setCellData(i, "bilgClntNo", ed_hhactcust.getValue());   //CUSTOMER   
            ds.setCellData(i, "bilgClntNm", txt_hhactcustnm.getValue());   //CUSTOMER name   

            await scwin.f_sellingUnitLoading();
            ds.setCellData(i, "fareUnit", ds_sellingUnit.getCellData(0, "code"));
            ds.setCellData(i, "drcrCls", "D"); // DR/CR         
            ds.setCellData(i, "locPtnCls", "1"); //국내 : 1, 해외 :2 
        } else if (gubun == "1") {
            ds.setCellData(i, "bilgClntNo", ed_hhagent.getValue());
            ds.setCellData(i, "bilgClntNm", txt_hhagentnm.getValue());   //partner name 

            await scwin.f_partnerUnitLoading();
            ds.setCellData(i, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
            ds.setCellData(i, "drcrCls", "C"); // DR/CR         
            ds.setCellData(i, "locPtnCls", "2"); //국내 : 1, 해외 :2 
        } else if (gubun == "2") {
            //ds.setCellData(i, "pchsClntNo", ed_hhliner.getValue()); 
            //ds.setCellData(i, "pchsClntNm", txt_hhlinernm.getValue());   //Liner name

            await scwin.f_buyingUnitLoading();
            ds.setCellData(i, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
            ds.setCellData(i, "pchsTyp", "1");
            ds.setCellData(i, "drcrCls", "C"); // DR/CR         
            ds.setCellData(i, "locPtnCls", "1"); //국내 : 1, 해외 :2  
        }

        ds.setCellData(i, "rsltsStdDt", scwin.hd_creadyDt);  //실적일 
        ds.setCellData(i, "exRateTyp", lc_hhexgb.getValue());  //exgb

        ds.modifyRowStatus(i, "C"); // 1

    }

    //unit처리.
    if (gubun == "0") {
        scwin.f_SellingSum();
    } else if (gubun == "1") {
        scwin.f_PartnerSum();
    } else if (gubun == "2") {
        scwin.f_BuyingSum();
    }

};
//-------------------------------------------------------------------------
//buying 데이터를 selling으로 copy 한다
// 1. BUYING에서 전도금코드(J,K) 사용시, SELLING에는 일반코드로 사용
// 2. 그외의 코드는 SELLING, BUYING 그대로 사용
//-------------------------------------------------------------------------	
scwin.f_copyFromBuyingToSelling = async function () {
    if (ds_buying.getRowCount() == 0 || ds_selling.getRowCount() > 0) {
        await $c.win.alert("buying 데이터가 없거나, selling 데이터가 이미 있는 경우는 해당 기능을 사용할 수 없습니다");
        return false;
    } else {
        for (var i = 0; i < ds_buying.getRowCount(); i++) {
            var code = ds_buying.getCellData(i, "fareEngCd");
            var param1 = "";
            var sellRow = ds_selling.getRowPosition() || 0;

            if (code.substring(code.length - 1) == "J") {
                await scwin.f_addRow(1);
                param1 = code.substring(0, code.length - 1);

                // ds_SellingCode.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveFreightCodeInfo&param1=" + param1;
                // ds_SellingCode.Reset();
                await scwin.f_commCodeSync("ilCommonEBC", "retriveFreightCodeInfo", param1);

                ds_SellingCode.setJSON(ds_tmpCode.getAllJSON(), false);

                ds_selling.setCellData(i, "sellSeq", ds_buying.getCellData(i, "pchsSeq"));
                // ds_selling.setCellData(sellRow, "fareEngCd", ds_SellingCode.getCellData(0, "col1"));
                // ds_selling.setCellData(sellRow, "sellItemCd", ds_SellingCode.getCellData(0, "col4"));
                // ds_selling.setCellData(sellRow, "fareEngNm", ds_SellingCode.getCellData(0, "col2"));
                ds_selling.setCellData(i, "fareEngCd", ds_SellingCode.getCellData(0, "col1"));
                ds_selling.setCellData(i, "sellItemCd", ds_SellingCode.getCellData(0, "col4"));
                ds_selling.setCellData(i, "fareEngNm", ds_SellingCode.getCellData(0, "col2"));

                ds_selling.setCellData(i, "fareGrpCd", ds_buying.getCellData(i, "fareGrpCd"));
                ds_selling.setCellData(i, "crcCd", ds_buying.getCellData(i, "crcCd"));
                ds_selling.setCellData(i, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
                ds_selling.setCellData(i, "chgWt", ds_buying.getCellData(i, "chgWt"));
                ds_selling.setCellData(i, "sellUpr", ds_buying.getCellData(i, "pchsUpr"));
                ds_selling.setCellData(i, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
                ds_selling.setCellData(i, "exRate", ds_buying.getCellData(i, "exRate"));
                ds_selling.setCellData(i, "sellAmt", ds_buying.getCellData(i, "pchsAmt"));
                ds_selling.setCellData(i, "vatAmt", ds_buying.getCellData(i, "vat"));
                ds_selling.setCellData(i, "usdAmt", ds_buying.getCellData(i, "usdAmt"));

                ds_selling.setCellData(i, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
                ds_selling.setCellData(i, "vatYn", ds_buying.getCellData(i, "vatYn"));


            } else if (code.substring(code.length - 1) == "K") {
                await scwin.f_addRow(1);
                param1 = code.substring(0, code.length - 1) + "V";
                // ds_SellingCode.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveFreightCodeInfo&param1=" + param1;
                // ds_SellingCode.Reset();
                await scwin.f_commCodeSync("ilCommonEBC", "retriveFreightCodeInfo", param1);
                ds_SellingCode.setJSON(ds_tmpCode.getAllJSON(), false);

                ds_selling.setCellData(i, "sellSeq", ds_buying.getCellData(i, "pchsSeq"));
                // ds_selling.setCellData(sellRow, "fareEngCd", ds_SellingCode.getCellData(0, "col1"));
                // ds_selling.setCellData(sellRow, "sellItemCd", ds_SellingCode.getCellData(0, "col4"));
                // ds_selling.setCellData(sellRow, "fareEngNm", ds_SellingCode.getCellData(0, "col2"));
                ds_selling.setCellData(i, "fareEngCd", ds_SellingCode.getCellData(0, "col1"));
                ds_selling.setCellData(i, "sellItemCd", ds_SellingCode.getCellData(0, "col4"));
                ds_selling.setCellData(i, "fareEngNm", ds_SellingCode.getCellData(0, "col2"));

                ds_selling.setCellData(i, "fareGrpCd", ds_buying.getCellData(i, "fareGrpCd"));
                ds_selling.setCellData(i, "crcCd", ds_buying.getCellData(i, "crcCd"));
                ds_selling.setCellData(i, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
                ds_selling.setCellData(i, "chgWt", ds_buying.getCellData(i, "chgWt"));
                ds_selling.setCellData(i, "sellUpr", ds_buying.getCellData(i, "pchsUpr"));
                ds_selling.setCellData(i, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
                ds_selling.setCellData(i, "exRate", ds_buying.getCellData(i, "exRate"));
                ds_selling.setCellData(i, "sellAmt", ds_buying.getCellData(i, "pchsAmt"));
                ds_selling.setCellData(i, "vatAmt", ds_buying.getCellData(i, "vat"));
                ds_selling.setCellData(i, "usSdAmt", ds_buying.getCellData(i, "usdAmt"));

                ds_selling.setCellData(i, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
                ds_selling.setCellData(i, "vatYn", ds_buying.getCellData(i, "vatYn"));

            } else {
                await scwin.f_addRow(1);

                ds_selling.setCellData(i, "sellSeq", ds_buying.getCellData(i, "pchsSeq"));
                ds_selling.setCellData(i, "fareEngCd", ds_buying.getCellData(i, "fareEngCd"));
                ds_selling.setCellData(i, "fareEngNm", ds_buying.getCellData(i, "fareEngNm"));
                ds_selling.setCellData(i, "fareGrpCd", ds_buying.getCellData(i, "fareGrpCd"));
                ds_selling.setCellData(i, "sellItemCd", ds_buying.getCellData(i, "selpchItemCd"));
                ds_selling.setCellData(i, "crcCd", ds_buying.getCellData(i, "crcCd"));
                ds_selling.setCellData(i, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
                ds_selling.setCellData(i, "chgWt", ds_buying.getCellData(i, "chgWt"));
                ds_selling.setCellData(i, "sellUpr", ds_buying.getCellData(i, "pchsUpr"));
                ds_selling.setCellData(i, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
                ds_selling.setCellData(i, "exRate", ds_buying.getCellData(i, "exRate"));
                ds_selling.setCellData(i, "sellAmt", ds_buying.getCellData(i, "pchsAmt"));
                ds_selling.setCellData(i, "vatAmt", ds_buying.getCellData(i, "vat"));
                ds_selling.setCellData(i, "usdAmt", ds_buying.getCellData(i, "usdAmt"));

                ds_selling.setCellData(i, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
                ds_selling.setCellData(i, "vatYn", ds_buying.getCellData(i, "vatYn"));

            }
        }
        scwin.cfViewTab(0);
    }
};

scwin.f_pkgChange = function (clsCd) {
    var chngValue = 0;
    if (clsCd == "Weight") {
        chngValue = ed_hhgwgt.getValue() / 1000;
    }
    if (clsCd == "Measure") {
        chngValue = ed_hhmsr.getValue();
    }

    if (scwin.tabNo == 0) {
        for (var i = 0; i < ds_selling.getRowCount(); i++) {
            if (ds_selling.getCellData(i, "chgWt") != 1) {
                ds_selling.setCellData(i, "chgWt", chngValue);

                if (ds_selling.getCellData(i, "crcCd") == "USD") {
                    ds_selling.setCellData(i, "sellAmtFcrc", (ds_selling.getCellData(i, "chgWt") || 0) * (ds_selling.getCellData(i, "sellUpr") || 0));
                    ds_selling.setCellData(i, "sellAmt", (ds_selling.getCellData(i, "sellAmtFcrc") || 0) * (ds_selling.getCellData(i, "exRate") || 0));
                }
                if (ds_selling.getCellData(i, "crcCd") == "KRW") {
                    ds_selling.setCellData(i, "sellAmt", (ds_selling.getCellData(i, "chgWt") || 0) * (ds_selling.getCellData(i, "sellUpr") || 0));
                }
            }
        }
    }

    if (scwin.tabNo == 1) {
        for (var i = 0; i < ds_partner.getRowCount(); i++) {
            if (ds_partner.getCellData(i, "chgWt") != 1) {
                ds_partner.setCellData(i, "chgWt", chngValue);

                if (ds_partner.getCellData(i, "crcCd") == "USD") {
                    ds_partner.setCellData(i, "sellAmtFcrc", (ds_partner.getCellData(i, "chgWt") || 0) * (ds_partner.getCellData(i, "sellUpr") || 0));
                    ds_partner.setCellData(i, "sellAmt", (ds_partner.getCellData(i, "sellAmtFcrc") || 0) * (ds_partner.getCellData(i, "exRate") || 0));
                }
                if (ds_partner.getCellData(i, "crcCd") == "KRW") {
                    ds_partner.setCellData(i, "sellAmt", (ds_partner.getCellData(i, "chgWt") || 0) * (ds_partner.getCellData(i, "sellUpr") || 0));
                }
            }
        }
    }

    if (scwin.tabNo == 2) {
        for (var i = 1; i <= ds_buying.CountRow; i++) {
            if (ds_buying.getCellData(i, "chgWt") != 1) {
                ds_buying.setCellData(i, "chgWt", chngValue);

                if (ds_buying.getCellData(i, "crcCd") == "USD") {
                    ds_buying.setCellData(i, "pchsAmtFcrc", (ds_buying.getCellData(i, "chgWt") || 0) * (ds_buying.getCellData(i, "pchsUpr") || 0));
                    ds_buying.setCellData(i, "pchsAmt", (ds_buying.getCellData(i, "pchsAmtFcrc") || 0) * (ds_buying.getCellData(i, "exRate") || 0));
                }
                if (ds_selling.getCellData(i, "crcCd") == "KRW") {
                    ds_buying.setCellData(i, "pchsAmt", (ds_buying.getCellData(i, "chgWt") || 0) * ds_buying.getCellData(i, "pchsUpr"));
                }
            }
        }
    }
};

