scwin.on_ds_houseblList_load = function () {
    if (ds_houseblList.getRowCount() > 0) {
        var r = 0;
        var hhexrate = ds_houseblList.getCellData(r, "hhexrate");
        var hhcur = ds_houseblList.getCellData(r, "hhcur");
        var hhuexrate = ds_houseblList.getCellData(r, "hhuexrate");
        if (hhexrate && hhexrate !== "0") {
            scwin.exRate1 = hhexrate;
            scwin.crc = hhcur;
            scwin.exRateCheck = "3";
        }
        if (hhuexrate && hhuexrate !== "0") {
            scwin.exRate2 = hhuexrate;
        }
    }
};

//---------------------------------------------------------
