scwin.on_ds_selling_load = function () {
    if (ds_selling.getRowCount() > 0 && ds_selling.getCellData(0, "tabIndex") == "0") {
        scwin.f_chgGridColumnToHouseBlDs("0", ds_selling);
    }
};
scwin.on_ds_partner_load = function () {
    if (ds_partner.getRowCount() > 0 && ds_partner.getCellData(0, "tabIndex") == "1") {
        scwin.f_chgGridColumnToHouseBlDs("1", ds_partner);
    }
};
scwin.on_ds_buying_load = function () {
    if (ds_buying.getRowCount() > 0 && ds_buying.getCellData(0, "tabIndex") == "2") {
        scwin.f_chgGridColumnToHouseBlDs("2", ds_buying);
    }
};

//---------------------------------------------------------
// Excel 다운로드
//---------------------------------------------------------
scwin.f_RunExcel = async function (dataId, gridId) {
    var sheetName = "";
    var fileName = "";
    var spanV = 0;
    if (gridId == gr_selling) {
        sheetName = "Selling List";
        fileName = "Selling List.xlsx";
        spanV = 18;
    } else if (gridId == gr_partner) {
        sheetName = "Partner List";
        fileName = "Partner List.xlsx";
        spanV = 22;
    } else if (gridId == gr_buying) {
        sheetName = "Buying List";
        fileName = "Buying List.xlsx";
        spanV = 23;
    }


    if (await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
        var options = {
            fileName: fileName,
            sheetName: sheetName,
            startRowIndex: 2,
            startColumnIndex: 0,
            type: 1,
            columnMove: true, //그리드 컬럼이동시 이동된 상태로 다운로드 유무 ( "true"인경우 컬럼이동 순서대로 출력 )
        };

        var infoArr = [{
            rowIndex: 0,
            colIndex: 0,
            rowSpan: 1,
            colSpan: spanV,
            text: sheetName,
            textAlign: "center",
            fontSize: 12,
            drawBorder: false
        }];

        $c.data.downloadGridViewExcel(gridId, options, infoArr);
    }
};

