scwin.f_setupApi = function () {
    var sURL = "ftp://172.21.1.42:7000/Home/Setup/Setup_CarrierAPI.exe";
    window.open(sURL);
};

scwin.f_openApi = function () {
    var linecode = "";
    try {
        ds_line_condition.setCellData(0, "hhliner", ed_hhliner.getValue());

        $c.sbm.execute(sbm_retrieve_linecode);

        linecode = ds_linecode.Namevalue(1, "cdNm");
        var objWSH = new ActiveXObject("WScript.Shell");
        var cmd = "C:\\dbexp_scrap1\\upgrade.exe job=invsearch2&linecode=" + linecode
            + "&no=" + (cnd_ed_hhmblno.getValue() || "")
            + "&bound=I&callerID=IH&hblno=" + (cnd_ed_hhblno.getValue() || "")
            + "&docuno=" + (cnd_lc_mhno.getValue() || "");
        objWSH.Run(cmd, 1, true);
    } catch (e) {
        $c.win.alert("API 실행을 지원하지 않는 환경입니다.");
    }
};

