scwin.f_GridResultdateChange = async function (rtnList) {
    if (ds_retrieve.get("tabIndex") == "0" || ds_retrieve.get("tabIndex") == "") { // Selling 
        if (ds_selling.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Selling Information"]); //  @이(가) 존재하지 않습니다.		
        } else {
            if (await $c.win.confirm(E_MSG_CM_CRM_001)) { //저장하시겠습니까?	
                for (var i = 0; i < ds_selling.getRowCount(); i++) {
                    if ($c.util.isEmpty(ds_selling.getCellData(i, "certiNo"))) {
                        ds_selling.setCellData(i, "rsltsStdDt", rtnList[1]);
                    }
                }
            }
        }
    } else if (ds_retrieve.get("tabIndex") == "1") { //partner
        if (ds_partner.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Partner Information"]); //  @이(가) 존재하지 않습니다.	
        } else {
            if (await $c.win.confirm(E_MSG_CM_CRM_001)) { //저장하시겠습니까?	
                for (var i = 0; i < ds_partner.getRowCount(); i++) {
                    if ($c.util.isEmpty(ds_partner.getCellData(i, "certiNo"))) {
                        ds_partner.setCellData(i, "rsltsStdDt", rtnList[1]);
                    }
                }
            }
        }
    } else if (ds_retrieve.get("tabIndex") == "2") { // Buying 
        if (ds_buying.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Buying Information"]); //  @이(가) 존재하지 않습니다.	
        } else {
            if (await $c.win.confirm(E_MSG_CM_CRM_001)) { //저장하시겠습니까?	
                for (var i = 0; i < ds_buying.getRowCount(); i++) {
                    if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsCertiNo"))) {
                        ds_buying.setCellData(i, "rsltsStdDt", rtnList[1]);
                    }
                }
            }
        }
    }
};
