scwin.f_openPgm = async function (name) {
    if (name == "Partner") {
        $c.win.openMenu(
            "Partner Statement",
            "/ui/il/acc/acpar/ac_104_01_01b.xml",
            "ac_104_01_01b",
            {
                kcomcd: scwin.hd_kcomcd,
                seaair: "S",
                iogb: scwin.hd_hhio,
                blno: cnd_ed_hhblno.getValue(),
                mblno: "",
                mhno: cnd_lc_mhno.getValue()
            },
            { openAction: "exist" }
        );

    } else if (name == "Invoice") {
        $c.win.openMenu(
            "Invoice",
            "/ui/il/acc/acinv/ac_101_01_01b.xml",
