        );

    } else if (name == "Profit") {
        $c.win.openMenu(
            "Booking Sheet",
            "/ui/il/pfm/pfbs/pe_101_01_01b.xml",
            "pe_101_01_01b",
            {
                kcomcd: scwin.hd_kcomcd,
                seaair: "S",
                iogb: scwin.hd_hhio,
                blno: cnd_ed_hhblno.getValue(),
                mblno: cnd_ed_hhblno.getValue(),
                mhno: cnd_lc_mhno.getValue()
            },
            { openAction: "exist" }
        );

    } else if (name == "HouseBLFind") {
        $c.win.openMenu(
            "House B/L Search",
            "/ui/il/seaout/sobl/se_105_01_02b.xml",
            "se_105_01_02b",
            {
                hhio: scwin.hd_hhio
