        );
    } else if (name == "HouseBLHeader") {
        $c.win.openMenu(
            "Import House B/L",
            "/ui/il/seainb/sibl/se_201_01_01b.xml",
            "se_201_01_01b",
            {
                linkcheck: "2",
                kcomcd: scwin.hd_kcomcd,
                blno: cnd_ed_hhblno.getValue(),
                mhno: cnd_lc_mhno.getValue()
            },
            { openAction: "exist" }
        );
    } else if (name == "MFreight") {
        $c.win.openMenu(
            "Import Master B/L Freight",
            "/ui/il/seainb/sibl/se_202_01_02b.xml",
            "se_202_01_02b",
            {
                linkcheck: "6",
                kcomcd: scwin.hd_kcomcd,
                blno: cnd_ed_hhblno.getValue(),
                mhno: cnd_lc_mhno.getValue()
            },
            { openAction: "exist" }
        );
    } else if (name == "paymentINV") {
        $c.win.openMenu(
            "Payment Invoice",
            "/ui/il/acc/acpay/ac_106_01_01b.xml",
            "ac_106_01_01b",
            {
                kcomcd: scwin.hd_kcomcd,
                seaair: "S",
                iogb: scwin.hd_hhio,
                blno: cnd_ed_hhblno.getValue(),
                mhno: cnd_lc_mhno.getValue()
            },
            { openAction: "exist" }
        );
    }
};

// 공통 코드조회 (param1~4)
// - sysCd 생략 시 "ilCommonEBC" 기본
scwin.f_commCode = async function (sysCd, queryId, param1, param2, param3, param4) {
    // sysCd 생략 호출 허용: f_commCode("queryId", p1, p2 ...)
    if (queryId == undefined) {
        queryId = sysCd;
        sysCd = "ilCommonEBC";
        param4 = param3;
        param3 = param2;
        param2 = param1;
        param1 = "";
    }

    var params = {
        sysCd: sysCd || "ilCommonEBC",
        queryId: queryId || "",
        param1: (param1 == undefined ? "" : param1),
        param2: (param2 == undefined ? "" : param2),
        param3: (param3 == undefined ? "" : param3),
        param4: (param4 == undefined ? "" : param4)
    };

    dma_combo.setJSON(params);
    await $c.sbm.execute(sbm_combo);
};
scwin.f_commCodeSync = async function (sysCd, queryId, param1, param2, param3, param4) {
    // sysCd 생략 호출 허용: f_commCode("queryId", p1, p2 ...)
    if (queryId == undefined) {
        queryId = sysCd;
        sysCd = "ilCommonEBC";
        param4 = param3;
        param3 = param2;
        param2 = param1;
        param1 = "";
    }

    var params = {
        sysCd: sysCd || "ilCommonEBC",
        queryId: queryId || "",
        param1: (param1 == undefined ? "" : param1),
        param2: (param2 == undefined ? "" : param2),
        param3: (param3 == undefined ? "" : param3),
        param4: (param4 == undefined ? "" : param4)
    };

    dma_combo.setEmptyValue();
    dma_combo.setJSON(params);
    await $c.sbm.execute(sbm_combo_sync);
};
scwin.sbm_combo_onsubmitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {

        //var rs = ds_combo; // ✅ 실제 응답 DataList로 변경

        //==================
        // 1) MHNO(HH) 처리
        //==================
        if (scwin._comboTarget == "HMHNO1") {
            ds_hmhno.setJSON(e.responseJSON.GAUCE);

            // 비어있으면 NONE 세팅
            if (ds_hmhno.getRowCount() == 0) {
                if (scwin.statusFlag != "C") {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["House No"]); // ✅ 이제 에러 안남
                }

                var r0 = ds_hmhno.insertRow(0);
                ds_hmhno.setCellData(r0, "code", "NONE");
                ds_hmhno.setCellData(r0, "name", "NONE");
                cnd_lc_mhno.setValue("NONE");
            }
            scwin._comboTarget = "";
            return;
        }

        //==================
        if (scwin._comboTarget == "HMHNO2") {
            ds_hmhno2.setJSON(e.responseJSON.GAUCE);
            // 비어있으면 NONE 세팅
            if (ds_hmhno2.getRowCount() == 0) {
                if (scwin.statusFlag != "C") {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["House No"]); // ✅ 이제 에러 안남
                }

                var r0 = ds_hmhno2.insertRow(0);
                ds_hmhno2.setCellData(r0, "code", "NONE");
                ds_hmhno2.setCellData(r0, "name", "NONE");
                srch_ed_hhblno.setValue("NONE");
            }
            scwin._comboTarget = "";
            return;
        }

        //==================
        // 1) INVOICE 처리
        //==================
        if (scwin._comboTarget == "INVOICE") {
            ds_invoiceCheck.setJSON(e.responseJSON.GAUCE);
            if (ds_invoiceCheck.getCellData(ds_invoiceCheck.getRowPosition(), "code") != "0") {
                scwin.invoiceCheck = "1";
            }

            // 조회 후 후처리
            scwin.f_afterRetrieve2();

        } else if (scwin._comboTarget == "INVOICE_DEL") { // 삭제 호출 시 분기 처리
            ds_invoiceCheck.setJSON(e.responseJSON.GAUCE);
            if (ds_invoiceCheck.getCellData(ds_invoiceCheck.getRowPosition(), "code") != "0") {
                scwin.invoiceCheck = "1";
            }
            scwin.f_afterdelete();
        }

        //==================
        // 2) exRateTarget 처리 (HOUSE/SELLING/BUYING/PARTNER)
        //==================
        if (scwin._comboTarget == "HOUSE") {
            ds_exHouseRate.setJSON(e.responseJSON.GAUCE);

            ed_hhexrate.setValue(ds_exHouseRate.getCellData(0, "code") || "");
            ed_hhuexrate.setValue(ds_exHouseRate.getCellData(0, "name") || "");

            if ($c.util.isEmpty(ed_hhexrate.getValue()) && ed_hhcur.getValue() != "KRW") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Ex-Rate"]);
                scwin.exRateCheck = "1";
            } else {
                scwin.exRateCheck = "2";
                scwin.exRate1 = ed_hhexrate.getValue();
                scwin.exRate2 = ed_hhuexrate.getValue();
                scwin.crc = ed_hhcur.getValue();
            }
        } else if (scwin._comboTarget == "SELLING") {
            ds_exHouseRate.setJSON(e.responseJSON.GAUCE);

            ds_selling.setCellData(scwin._exRateRow, "exRate", ds_exHouseRate.getCellData(0, "CODE"));
            if ($c.util.isEmpty(ds_exHouseRate.getCellData(0, "CODE")) && scwin._exRateCur != "KRW") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Ex-Rate"]);
            }

        } else if (scwin._comboTarget == "BUYING") {
            ds_exHouseRate.setJSON(e.responseJSON.GAUCE);

            ds_buying.setCellData(scwin._exRateRow, "exRate", ds_exHouseRate.getCellData(0, "CODE"));
            if ($c.util.isEmpty(ds_exHouseRate.getCellData(0, "CODE")) && scwin._exRateCur != "KRW") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Ex-Rate"]);
            }
        } else if (scwin._comboTarget == "PARTNER") {
            ds_exHouseRate.setJSON(e.responseJSON.GAUCE);

            ds_partner.setCellData(scwin._exRateRow, "exRate", ds_exHouseRate.getCellData(0, "CODE"));
            if ($c.util.isEmpty(ds_exHouseRate.getCellData(0, "CODE")) && scwin._exRateCur != "KRW") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Ex-Rate"]);
            }
        }

        //tobe 추가
        if (scwin._comboTarget == 'CURRENCY') {
            ds_currencyCode.setJSON(e.responseJSON.GAUCE);
            scwin._comboTarget = "";
        }

        //tobe 추가
        if (scwin._comboTarget == "CONTAINER_TYPE") {
            ds_containerType.setJSON(e.responseJSON.GAUCE);
            scwin._comboTarget = "";
        }
    }
};

scwin.f_afterRetrieve2 = function () {
    scwin.f_Set("RETRIEVE");
    scwin.f_SellingSum();
    scwin.f_PartnerSum();
    scwin.f_BuyingSum();
    scwin.f_afterRetrieveForlinkcheck9();
};
scwin.f_afterRetrieveForlinkcheck9 = async function () {
    if (scwin.v_linkcheck != "9") {
        return true;
    }
    scwin.f_Set("UPDATE");
    var row_cnt = parseInt(scwin.p_row_cnt, 10) || 0;
    var data = scwin.p_data || "";

    if (!data) return false;

    // data: "A_B_C$D_E_F..." 형태 가정
    var rtnValues = data.split("$");
    if (!rtnValues || rtnValues.length == 0) return false;

    // row_cnt만큼만 파싱 (data가 더 짧으면 실제 길이만)
    var loopCnt = Math.min(row_cnt, rtnValues.length);

    // 2차원 배열로 변환
    // [ [fromCd, crcCd, pchsAmtFcrc, exRate, pchsAmt, chgWt, pchsUpr], ... ]
    var rows = [];
    for (var t = 0; t < loopCnt; t++) {
        rows[t] = String(rtnValues[t] || "").split("_");
    }

    for (var idx = 0; idx < rows.length; idx++) {
        var arr = rows[idx];
        if (!arr || arr.length < 7) continue;

        var fromCd = String(arr[0] || "").trim();
        var crcCd = String(arr[1] || "").trim();
        var amtFcrc = arr[2];
        var exRate = arr[3];
        var pchsAmt = arr[4];
        var chgWt = arr[5];
        var pchsUpr = arr[6];

        scwin.f_addRow(3);

        // 새로 추가된 row index (보통 마지막)
        var row = ds_buying.getRowCount() - 1;
        if (row < 0) continue;

        // pchsSeq = 이전행 + 1
        var prevRow = row - 1;
        var prevSeq = 0;
        if (prevRow >= 0) {
            prevSeq = Number(ds_buying.getCellData(prevRow, "pchsSeq") || 0);
        }
        ds_buying.setCellData(row, "pchsSeq", prevSeq + 1);

        ds_line_condition.setCellData(0, "hhliner", ed_hhliner ? ed_hhliner.getValue() : "");
        ds_line_condition.setCellData(0, "fromCd", fromCd);

        // tr_retrieve_frtMapping.post() 대체: submission 실행 후 결과 대기
        await $c.sbm.execute(sbm_retrieve_frtMapping).then(function (rtn) {
            // ds_frtMapping 0행 결과 반영
            ds_buying.setCellData(row, "fareEngCd", ds_frtMapping.getCellData(0, "toCd"));
            ds_buying.setCellData(row, "fareEngNm", ds_frtMapping.getCellData(0, "description"));
            ds_buying.setCellData(row, "selpchItemCd", ds_frtMapping.getCellData(0, "dtlCd1"));
            ds_buying.setCellData(row, "fareGrpCd", ds_frtMapping.getCellData(0, "dtlCd2"));
            ds_buying.setCellData(row, "vatYn", ds_frtMapping.getCellData(0, "dtlCd3"));

            // 원본 데이터 세팅
            ds_buying.setCellData(row, "crcCd", crcCd);
            ds_buying.setCellData(row, "pchsAmtFcrc", amtFcrc);
            ds_buying.setCellData(row, "exRate", exRate);
            ds_buying.setCellData(row, "pchsAmt", pchsAmt);
            ds_buying.setCellData(row, "chgWt", chgWt);
            ds_buying.setCellData(row, "pchsUpr", pchsUpr);

            // USD면 usdAmt = pchsAmtFcrc
            if (ds_buying.getCellData(row, "crcCd") == "USD") {
                ds_buying.setCellData(row, "usdAmt", amtFcrc);
            }
        });
    }
};

