// gr_selling event=OnExit(Row,Colid,olddata)>
scwin.gr_selling_onafteredit = async function (rowIndex, columnIndex, value) {
    var row = rowIndex;
    var col = gr_selling.getColumnID(columnIndex);
    var olddata = ds_selling.getCellData(row, col);

    if (row < 0 || ds_selling.getRowCount() <= row) return;

    switch (col) {
        case "bilgClntNo":
            if (!$c.util.isEmpty(value)) {
                ds_selling.setCellData(row, "bilgClntNm", "");
                await scwin.f_PopUpGrid("SellingCustomer", row, "T", "F", "F");
            } else {
                ds_selling.setCellData(row, "bilgClntNo", "");
                ds_selling.setCellData(row, "bilgClntNm", "");
            }
            break;

        case "fareEngCd":
            if (!$c.util.isEmpty(value)) {
                ds_selling.setCellData(row, "fareEngNm", "");
                ds_selling.setCellData(row, "fareEngCd", value.toUpperCase());
                await scwin.f_PopUpGrid("SellingFcode", row, "T", "F", "F");
            } else {
                ds_selling.setCellData(row, "fareEngCd", "");
                ds_selling.setCellData(row, "fareEngNm", "");
            }

            scwin.f_sellingAmtFcrc(row, col, olddata);
            scwin.f_sellingAmt(row, col, olddata);
            scwin.f_sellingVat(row, col, olddata);
            scwin.f_sellingUsdAmt(row, col, olddata);
            break;

        case "crcCd":
        case "chgWt":
        case "sellUpr":
            scwin.f_sellingAmtFcrc(row, col, olddata);
            scwin.f_sellingAmt(row, col, olddata);
            scwin.f_sellingVat(row, col, olddata);
            scwin.f_sellingUsdAmt(row, col, olddata);
            break;

        case "exRate":
            scwin.f_sellingAmt(row, col, olddata);
            break;

        case "sellAmt":
            scwin.f_sellingVat(row, col, olddata);
            break;

        case "vatAmt":
            scwin.f_sellingUsdAmt(row, col, olddata);
            break;

        case "fareUnit": //for=gr_selling event=OnCloseUp(Row,Colid)
            await scwin.f_packageRateSellingLoading(row, col);
            scwin.f_sellingTariffRateLoading();
            break;
    }
};

