//for=ds_selling event=onColumnChanged(row,colid)
scwin.ds_selling_oncelldatachange = async function (info) {
    var row = info.rowIndex;
    var colid = info.colID;

    // Currency event
    if (colid == "crcCd") {
        if (ds_selling.getCellData(row, "crcCd") != "") {
            var idxArr = ds_currencyCode.getMatchedIndex(0, ds_selling.getCellData(row, "crcCd"));
            if (!(idxArr.length > 0)) {  // 값이 없을때
                ds_selling.setCellData(row, "exRate", "");
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Currency Information"]); //  @이(가) 존재하지 않습니다.
            } else {
                if (ds_selling.getCellData(row, "crcCd") != "KRW") {
                    await scwin.f_ExRateSellingGridLoading();
                }
            }
        } else {
            return;
        }
    }

    // sum값 call
    if (colid == "sellAmtFcrc" || colid == "sellAmt" || colid == "vatAmt") {
        await scwin.f_SellingSum();
    }
};

