//==================
// header checkbox 공통 처리
//==================
scwin._headCheckApply = function (ds, checked) {
    var isOn = (checked == true || checked == "1" || String(checked).toLowerCase() == "true");
    var v = isOn ? "T" : "F";

    var rc = ds.getRowCount();
    for (var r = 0; r < rc; r++) {
        ds.setCellData(r, "chk", v);
    }
};
 **/

