// tobe추가 : 그리드 readonly로 editable 설정하기 
scwin.f_setGridColumnsReadOnly = function (gridObj, readOnly) {
    var editNcol = ["column50", "bilgClntNm", "pchsClntNm", "fareEngNm", "usdAmt", "pchsCertiNo", "certiNo", "trfUpr", "regName"]; //해당 컬럼은 무조건 readOnly

    // 그리드 컬럼 개수 가져오기
    var colCnt = gridObj.getColumnCount();

    for (var i = 0; i < colCnt; i++) {
        var colId = gridObj.getColumnID(i);


        // editNcol 배열에 포함되어 있는지 확인
        if (editNcol.indexOf(colId) == -1) { //미포함
            gridObj.setColumnReadOnly(colId, readOnly);
        }
    }
};

scwin.sbm_retrieveF = async function (e) {
    txt_totalSelling.setValue(ds_selling.getRowCount());
    txt_totalPartner.setValue(ds_partner.getRowCount());
    txt_totalBuying.setValue(ds_buying.getRowCount());

    // tr_retrieve" event="OnSuccess()"
    if (ds_houseblList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.f_Set("INIT");
        scwin.f_Check();

        // 이벤트 처리 때문에 분리 
        scwin.f_afterRetrieveForlinkcheck9();
    } else {
        ds_houseblList.setRowPosition(0);
        ds_selling.setRowPosition(0);
        ds_buying.setRowPosition(0);
        ds_partner.setRowPosition(0);

        //tobe추가
        scwin.hd_hhdanggb = ds_houseblList.getRowJSON(0).hhdanggb;
        scwin.hd_creadyDt = ds_houseblList.getRowJSON(0).creadyDt;

        if (tbc_main.getSelectedTabIndex() == 0) {
            gr_selling.setFocusedCell(0, 1);

        }
        if (tbc_main.getSelectedTabIndex() == 1) {
            gr_partner.setFocusedCell(0, 1);
        }
        if (tbc_main.getSelectedTabIndex() == 2) {
            gr_buying.setFocusedCell(0, 1);
        }


        scwin.f_invoiceCheck();

        // INVOICE 후에 처리 하게 
        /*
        scwin.f_Set("RETRIEVE");
        scwin.f_SellingSum();
        scwin.f_PartnerSum();
        scwin.f_BuyingSum();

        scwin.f_afterRetrieveForlinkcheck9();
        */
    }
};

